module ripple_carry_adder (  
    input [3:0] rc_add_A,  
    input [3:0] B,  
    input Cin,  
    output [4:0] Sum  
);  
    wire [3:0] C;  
    assign Sum[0] = rc_add_A[0] ^ B[0] ^ Cin;  
    assign C[0] = (rc_add_A[0] & B[0]) | (Cin & (rc_add_A[0] ^ B[0]));  
    assign Sum[1] = rc_add_A[1] ^ B[1] ^ C[0];  
    assign C[1] = (rc_add_A[1] & B[1]) | (C[0] & (rc_add_A[1] ^ B[1]));  
    assign Sum[2] = rc_add_A[2] ^ B[2] ^ C[1];  
    assign C[2] = (rc_add_A[2] & B[2]) | (C[1] & (rc_add_A[2] ^ B[2]));  
    assign Sum[3] = rc_add_A[3] ^ B[3] ^ C[2];  
    assign Sum[4] = (rc_add_A[3] & B[3]) | (C[2] & (rc_add_A[3] ^ B[3]));  
endmodule
